import React, { useMemo, useState } from "react";
import { createClient } from "@supabase/supabase-js";
import {
    Card,
    CardContent,
    CardHeader,
    CardTitle,
} from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Separator } from "@/components/ui/separator";
import { Loader2, Eye, EyeOff, ShieldCheck, Mail, Lock, LogIn } from "lucide-react";

/**
 * Modern, production-ready Login screen
 * - Tailwind + shadcn/ui components
 * - Glassmorphism card, subtle animated background
 * - Password visibility toggle
 * - Loading/disabled states and inline errors
 * - Optional OAuth (Google) with Supabase
 * - Backwards compatible with your current "Login" table approach
 */

const SUPABASE_URL = (typeof import.meta !== "undefined" ? import.meta.env.VITE_SUPABASE_URL : undefined) || process.env.REACT_APP_SUPABASE_URL;
const SUPABASE_KEY = (typeof import.meta !== "undefined" ? import.meta.env.VITE_SUPABASE_KEY : undefined) || process.env.REACT_APP_SUPABASE_KEY;

const supabase = createClient(SUPABASE_URL, SUPABASE_KEY);

export default function Login({ onLoginSuccess }) {
    const [identifier, setIdentifier] = useState(""); // email OR username (kullanici_adi)
    const [password, setPassword] = useState("");
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState("");
    const [showPw, setShowPw] = useState(false);

    const isEmail = useMemo(() => /.+@.+\..+/.test(identifier), [identifier]);

    const handleSupabaseAuth = async () => {
        const { data, error } = await supabase.auth.signInWithPassword({
            email: identifier,
            password,
        });
        if (error) throw error;
        // Optionally fetch a profile row if you have a profile table
        const sessionUser = data?.user || null;
        localStorage.setItem("kullanici", JSON.stringify(sessionUser));
        return sessionUser;
    };

    // Fallback: your legacy table lookup ("Login" table with kullanici_adi/sifre)
    const handleLegacyTableLogin = async () => {
        const { data, error } = await supabase
            .from("Login")
            .select("*")
            .eq("kullanici_adi", identifier)
            .eq("sifre", password)
            .maybeSingle();

        if (error || !data) {
            const err = new Error("Hatalı kullanıcı adı veya şifre");
            err.code = "INVALID_CREDENTIALS";
            throw err;
        }

        // Tüm kullanıcı kaydını sakla (mevcut davranış)
        localStorage.setItem("kullanici", JSON.stringify(data));

        // REEL bilgileri (esnek alanlar)
        const reelUser =
            data?.Reel_kullanici ??
            data?.reel_kullanici ??
            data?.reelUserName ??
            data?.reel_username ??
            "";
        const reelPass =
            data?.Reel_sifre ??
            data?.reel_sifre ??
            data?.reelPassword ??
            data?.reel_password ??
            "";

        if (reelUser) localStorage.setItem("Reel_kullanici", reelUser);
        if (reelPass) localStorage.setItem("Reel_sifre", reelPass);
        if (reelUser && reelPass) {
            localStorage.setItem("reelCreds", JSON.stringify({ userName: reelUser, password: reelPass }));
        }

        return data;
    };

    const handleLogin = async (e) => {
        e.preventDefault();
        setLoading(true);
        setError("");

        try {
            if (isEmail) {
                await handleSupabaseAuth();
            } else {
                await handleLegacyTableLogin();
            }
            onLoginSuccess?.();
        } catch (err) {
            console.error("Login error:", err);
            setError(err?.message || "Beklenmeyen bir hata oluştu. Lütfen tekrar deneyin.");
        } finally {
            setLoading(false);
        }
    };

    const signInWithGoogle = async () => {
        try {
            setLoading(true);
            const { error } = await supabase.auth.signInWithOAuth({ provider: "google" });
            if (error) throw error;
            // Supabase will redirect; if using PKCE with a deep link, handle in your router
        } catch (err) {
            console.error(err);
            setError("Google ile giriş yapılamadı. Daha sonra tekrar deneyin.");
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="relative min-h-screen w-full overflow-hidden bg-gradient-to-br from-zinc-900 via-slate-900 to-neutral-900 text-white">
            {/* Decorative animated blobs */}
            <div className="pointer-events-none absolute -top-24 -left-24 h-72 w-72 rounded-full bg-fuchsia-500/20 blur-3xl animate-pulse" />
            <div className="pointer-events-none absolute -bottom-28 -right-24 h-96 w-96 rounded-full bg-cyan-500/20 blur-3xl animate-[pulse_8s_ease-in-out_infinite]" />

            <div className="container relative mx-auto flex min-h-screen max-w-7xl items-center justify-center px-4">
                <Card className="mx-auto w-full max-w-md border-white/10 bg-white/5 backdrop-blur-xl shadow-2xl shadow-black/40">
                    <CardHeader className="space-y-2 text-center">
                        <div className="mx-auto flex h-12 w-12 items-center justify-center rounded-2xl bg-white/10">
                            <ShieldCheck className="h-6 w-6" />
                        </div>
                        <CardTitle className="text-2xl font-semibold tracking-tight">
                            Giriş Yap
                        </CardTitle>
                        <p className="text-sm text-white/60">
                            {(isEmail ? "E-posta" : "Kullanıcı adı") + " ve şifrenizle devam edin"}
                        </p>
                    </CardHeader>

                    <CardContent>
                        {error && (
                            <div className="mb-4 rounded-xl border border-red-500/30 bg-red-500/10 p-3 text-red-200">
                                {error}
                            </div>
                        )}

                        <form onSubmit={handleLogin} className="space-y-5">
                            <div className="space-y-2">
                                <Label htmlFor="identifier">Kullanıcı Adı / E‑posta</Label>
                                <div className="relative">
                                    <Mail className="pointer-events-none absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-white/40" />
                                    <Input
                                        id="identifier"
                                        type="text"
                                        value={identifier}
                                        onChange={(e) => setIdentifier(e.target.value)}
                                        placeholder="ornek@site.com veya kullanici_adi"
                                        autoComplete="username"
                                        required
                                        className="pl-10 bg-white/5 border-white/10 text-white placeholder:text-white/40"
                                    />
                                </div>
                            </div>

                            <div className="space-y-2">
                                <Label htmlFor="password">Şifre</Label>
                                <div className="relative">
                                    <Lock className="pointer-events-none absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-white/40" />
                                    <Input
                                        id="password"
                                        type={showPw ? "text" : "password"}
                                        value={password}
                                        onChange={(e) => setPassword(e.target.value)}
                                        placeholder="••••••••"
                                        autoComplete="current-password"
                                        required
                                        className="pl-10 pr-10 bg-white/5 border-white/10 text-white placeholder:text-white/40"
                                    />
                                    <button
                                        type="button"
                                        aria-label={showPw ? "Şifreyi gizle" : "Şifreyi göster"}
                                        onClick={() => setShowPw((v) => !v)}
                                        className="absolute right-2 top-1/2 -translate-y-1/2 rounded-md p-2 text-white/60 hover:text-white"
                                    >
                                        {showPw ? <EyeOff className="h-4 w-4" /> : <Eye className="h-4 w-4" />}
                                    </button>
                                </div>
                            </div>

                            <div className="flex items-center justify-between text-sm">
                                <label className="flex items-center gap-2 text-white/70">
                                    <input type="checkbox" className="h-4 w-4 rounded border-white/20 bg-transparent" />
                                    Beni hatırla
                                </label>
                                <a className="text-white/70 underline-offset-4 hover:underline" href="#" onClick={(e) => e.preventDefault()}>
                                    Şifremi unuttum
                                </a>
                            </div>

                            <Button
                                type="submit"
                                disabled={loading}
                                className="w-full gap-2 rounded-xl bg-white text-black hover:bg-zinc-100"
                            >
                                {loading ? (
                                    <>
                                        <Loader2 className="h-4 w-4 animate-spin" /> Giriş yapılıyor…
                                    </>
                                ) : (
                                    <>
                                        <LogIn className="h-4 w-4" /> Giriş
                                    </>
                                )}
                            </Button>

                            <div className="py-1">
                                <Separator className="bg-white/10" />
                            </div>

                            <Button
                                type="button"
                                variant="outline"
                                disabled={loading}
                                onClick={signInWithGoogle}
                                className="w-full rounded-xl border-white/20 bg-white/5 text-white hover:bg-white/10"
                            >
                                Google ile devam et
                            </Button>

                            <p className="text-center text-xs text-white/50">
                                Devam ederek <a href="#" className="underline underline-offset-4">Kullanım Koşulları</a> ve <a href="#" className="underline underline-offset-4">Gizlilik</a>'i kabul etmiş olursunuz.
                            </p>
                        </form>
                    </CardContent>
                </Card>
            </div>
        </div>
    );
}
